PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?athlete
WHERE {
  ?event wdt:P31 wd:Q11436361;
         rdfs:label "1967 European Indoor Games"@en;
         wdt:P585 ?eventDate.
  FILTER (YEAR(?eventDate) = 1967)
  ?event wdt:P1454 ?competition.
  ?competition rdfs:label "Men's long jump"@en.
  ?competition wdt:P2281 ?athlete.
  ?athlete wdt:P27 wd:Q145;
         wdt:P19 wd:Q35884.
}

